export default function CustomDomainPurchaseGuidePage() {
  const { t } = useTranslation();
  const [selectedProvider, setSelectedProvider] = useState("Cloudflare");
  const [selectedStep, setSelectedStep] = useState(1);
  const selectedGuide =
    GUIDES.find(guide => guide.provider === selectedProvider) || GUIDES[0];
  const currentStep =
    selectedGuide.steps[selectedStep - 1] || selectedGuide.steps[0];

  function selectProvider(provider: string) {
    setSelectedProvider(provider);
    setSelectedStep(1);
  }

  return (
    <PageShell
      pageTitle={t("domainSetupGuideModal.title")}
      parentTitle={t("navigation.customDomain")}
      parentHref="/custom-domain"
    >
      <div className="space-y-6">
        <LocalizedLink
          to="/custom-domain"
          className="inline-flex items-center gap-2 text-sm font-medium text-(--fg-brand) hover:underline"
        >
          <ArrowLeft className="h-4 w-4" />
          {t("common.back") || "Back"} {t("navigation.customDomain")}
        </LocalizedLink>

        <section className="rounded-2xl border border-(--line-subtle) bg-(--bg-surface-primary) p-6">
          <div className="flex items-start gap-3">
            <div className="flex h-10 w-10 items-center justify-center rounded-xl bg-[rgba(188,135,255,0.12)] text-(--fg-brand)">
              <Globe className="h-5 w-5" />
            </div>
            <div>
              <h2 className="text-xl font-semibold text-(--fg-primary)">
                {t("domainSetupGuideModal.title")}
              </h2>
              <p className="mt-1 text-sm leading-6 text-(--fg-secondary)">
                {t("domainSetupGuideModal.subtitle")}
              </p>
            </div>
          </div>
        </section>

        <section className="rounded-2xl border border-(--line-subtle) bg-(--bg-surface-primary) p-6">
          <div className="mb-6 flex flex-wrap gap-2">
            {GUIDES.map(guide => {
              const isActive = guide.provider === selectedProvider;
              return (
                <button
                  key={guide.provider}
                  type="button"
                  onClick={() => selectProvider(guide.provider)}
                  className={`rounded-full border px-4 py-2 text-sm font-medium transition-colors ${
                    isActive
                      ? "border-(--line-brand) bg-[rgba(188,135,255,0.14)] text-(--fg-brand)"
                      : "border-(--line-subtle) text-(--fg-secondary) hover:bg-(--bg-hover) hover:text-(--fg-primary)"
                  }`}
                >
                  {guide.provider}
                </button>
              );
            })}
          </div>

          <div className="mb-6 flex flex-col gap-3 sm:flex-row sm:items-start sm:justify-between">
            <div>
              <h3 className="text-lg font-semibold text-(--fg-primary)">
                {selectedGuide.provider}
              </h3>
              <p className="mt-1 text-sm text-(--fg-secondary)">
                {t(selectedGuide.descriptionKey)}
              </p>
            </div>
            <a
              href={selectedGuide.link}
              target="_blank"
              rel="noopener noreferrer"
              className="inline-flex shrink-0 items-center gap-1.5 text-sm font-medium text-(--fg-brand) hover:underline"
            >
              {selectedGuide.linkText}
              <ExternalLink className="h-4 w-4" />
            </a>
          </div>

          <div className="grid gap-6 lg:grid-cols-[280px_1fr]">
            <aside className="rounded-xl border border-(--line-subtle) bg-(--bg-surface-secondary) p-3">
              <p className="mb-3 px-2 text-xs font-semibold uppercase tracking-[0.12em] text-(--fg-tertiary)">
                {t("domainSetupGuideModal.steps")}
              </p>
              <div className="space-y-1">
                {selectedGuide.steps.map((step, index) => {
                  const stepNumber = index + 1;
                  const isActive = selectedStep === stepNumber;
                  return (
                    <button
                      key={step.titleKey}
                      type="button"
                      onClick={() => setSelectedStep(stepNumber)}
                      className={`flex w-full items-start gap-3 rounded-lg px-2 py-2.5 text-left transition-colors ${
                        isActive
                          ? "bg-[rgba(188,135,255,0.14)] text-(--fg-primary)"
                          : "text-(--fg-secondary) hover:bg-(--bg-hover) hover:text-(--fg-primary)"
                      }`}
                    >
                      <span
                        className={`mt-0.5 flex h-6 w-6 shrink-0 items-center justify-center rounded-full text-xs font-semibold ${isActive ? "bg-[rgba(188,135,255,0.22)] text-(--fg-brand)" : "bg-(--bg-surface-primary) text-(--fg-tertiary)"}`}
                      >
                        {stepNumber}
                      </span>
                      <span className="text-sm font-medium leading-5">
                        {t(step.titleKey)}
                      </span>
                    </button>
                  );
                })}
              </div>
            </aside>

            <article className="rounded-xl border border-(--line-subtle) bg-(--bg-surface-secondary) p-5">
              <div className="mb-4 flex items-center gap-2">
                <span className="rounded-md bg-[rgba(188,135,255,0.14)] px-2 py-1 text-xs font-semibold text-(--fg-brand)">
                  {t("domainSetupGuideModal.step")} {selectedStep}
                </span>
                <span className="text-xs text-(--fg-secondary)">
                  {selectedGuide.provider}
                </span>
              </div>

              <h3 className="text-xl font-semibold text-(--fg-primary)">
                {t(currentStep.titleKey)}
              </h3>
              <p className="mt-2 text-sm leading-6 text-(--fg-secondary)">
                {t(currentStep.descriptionKey)}
              </p>

              {currentStep.imageUrl && (
                <ScreenshotPanel
                  imageUrl={currentStep.imageUrl}
                  title={t(currentStep.titleKey)}
                  imageAlt={
                    currentStep.imageAltKey
                      ? t(currentStep.imageAltKey)
                      : t("domainSetupGuideModal.stepIllustration")
                  }
                />
              )}

              {currentStep.link && currentStep.linkTextKey && (
                <a
                  href={currentStep.link}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="mt-4 inline-flex items-center gap-1.5 text-sm font-medium text-(--fg-brand) hover:underline"
                >
                  {t(currentStep.linkTextKey)}
                  <ExternalLink className="h-3.5 w-3.5" />
                </a>
              )}

              {currentStep.dns && (
                <DnsRecords
                  provider={selectedGuide.provider}
                  proxyNoteKeys={selectedGuide.proxyNoteKeys}
                />
              )}
            </article>
          </div>
        </section>
      </div>
    </PageShell>
  );
}

function DnsRecords({
  provider,
  proxyNoteKeys,
}: {
  provider: string;
  proxyNoteKeys?: string[];
}) {
  const { t } = useTranslation();
  return (
    <div className="ml-10 mt-4 space-y-4">
      <div className="rounded-xl border border-[rgba(29,246,181,0.22)] bg-[rgba(29,246,181,0.08)] p-4">
        <div className="mb-3 flex items-center gap-2 text-sm font-semibold text-[#1DF6B5]">
          <CheckCircle2 className="h-4 w-4" />
          {t("domainSetupGuideModal.requiredDnsRecords")}
        </div>
        <div className="grid gap-3 lg:grid-cols-2">
          <DnsBlock
            title="For apex domains, example.com"
            rows={[
              ...A_RECORD_IPS.map(ip => `Type: A | Name: @ | Value: ${ip}`),
              `Type: CNAME | Name: www | Value: ${GITHUB_PAGES_DOMAIN}`,
            ]}
          />
          <DnsBlock
            title="For subdomains, dex.example.com"
            rows={[`Type: CNAME | Name: dex | Value: ${GITHUB_PAGES_DOMAIN}`]}
          />
        </div>
      </div>

      {provider === "Cloudflare" && proxyNoteKeys && (
        <div className="rounded-xl border border-[rgba(188,135,255,0.22)] bg-[rgba(188,135,255,0.08)] p-4">
          <div className="mb-2 flex items-center gap-2 text-sm font-semibold text-(--fg-brand)">
            <Shield className="h-4 w-4" />
            {t("domainSetupGuideModal.cloudflareProxyTitle")}
          </div>
          <ul className="list-disc space-y-1.5 pl-5 text-sm leading-6 text-(--fg-secondary)">
            {proxyNoteKeys.map(key => (
              <li key={key}>{t(key)}</li>
            ))}
          </ul>
        </div>
      )}

      <div className="rounded-xl border border-[rgba(217,171,82,0.25)] bg-[rgba(217,171,82,0.08)] p-4">
        <div className="mb-2 flex items-center gap-2 text-sm font-semibold text-[#D9AB52]">
          <Mail className="h-4 w-4" />
          {t("domainSetupGuideModal.recommendedEmailSecurity")}
        </div>
        <p className="mb-3 text-sm leading-6 text-(--fg-secondary)">
          {t("domainSetupGuideModal.emailSecurityDesc")}
        </p>
        <DnsBlock
          title="TXT records"
          rows={[
            "Type: TXT | Name: @ | Value: v=spf1 -all",
            "Type: TXT | Name: _dmarc | Value: v=DMARC1; p=reject; sp=reject; aspf=s; adkim=s",
          ]}
        />
        <p className="mt-3 text-xs leading-5 text-(--fg-secondary)">
          {t("domainSetupGuideModal.recordsTellServers")}
        </p>
      </div>

      <div className="flex items-start gap-2 text-xs text-(--fg-secondary)">
        <Info className="mt-0.5 h-3.5 w-3.5 shrink-0" />
        <span>{t("domainSetupGuideModal.copyExactValues")}</span>
      </div>
    </div>
  );
}

function ScreenshotPanel({
  imageUrl,
  title: _title,
  imageAlt,
}: {
  imageUrl?: string;
  title: string;
  imageAlt: string;
}) {
  const [missing, setMissing] = useState(false);
  const { t } = useTranslation();

  return (
    <div className="mt-5 overflow-hidden rounded-xl border border-(--line-subtle) bg-(--bg-surface-primary)">
      {imageUrl && !missing ? (
        <img
          src={imageUrl}
          alt={imageAlt}
          onError={() => setMissing(true)}
          className="h-auto max-h-[420px] w-full object-contain"
        />
      ) : (
        <div className="flex min-h-[260px] flex-col items-center justify-center px-6 py-10 text-center">
          <div className="mb-3 flex h-12 w-12 items-center justify-center rounded-xl bg-[rgba(188,135,255,0.12)] text-(--fg-brand)">
            <Globe className="h-6 w-6" />
          </div>
          <p className="text-sm font-medium text-(--fg-primary)">
            {t("domainSetupGuideModal.stepIllustration")}
          </p>
          <p className="mt-1 max-w-md text-xs leading-5 text-(--fg-secondary)">
            {t("domainSetupGuideModal.imagePlaceholder")}
          </p>
          {imageUrl && (
            <p className="mt-3 font-mono text-xs text-(--fg-tertiary)">
              Expected asset: {imageUrl}
            </p>
          )}
        </div>
      )}
    </div>
  );
}

function DnsBlock({ title, rows }: { title: string; rows: string[] }) {
  return (
    <div>
      <p className="mb-2 text-xs font-semibold text-(--fg-primary)">{title}</p>
      <div className="space-y-1 rounded-lg border border-(--line-subtle) bg-(--bg-surface-primary) p-3 font-mono text-xs leading-5 text-(--fg-secondary)">
        {rows.map(row => (
          <div key={row}>{row}</div>
        ))}
      </div>
    </div>
  );
}
